from collections import defaultdict

class Solution(object):
    def minimumDistance(self, nums):
        # distance(i,j,k) = abs(i-j) + abs(j-k) + abs(k-i) = 2*(max-min)
        # For three sorted indices p < q < r: distance = 2*(r-p)
        # Minimize by choosing consecutive triples in sorted index list per value.
        positions = defaultdict(list)
        for i, v in enumerate(nums):
            positions[v].append(i)

        ans = float('inf')
        for v, idxs in positions.items():
            if len(idxs) < 3:
                continue
            for i in range(len(idxs) - 2):
                ans = min(ans, 2 * (idxs[i + 2] - idxs[i]))

        return ans if ans != float('inf') else -1
